local function NatDexExtension()
	local self = {
		version = "1.2.1",
		name = "Nat. Dex",
		author = "CyanSixFour, UTDZac",
		description = "Extension that allows for compatibility with the Emerald & FireRed Nat. Dex ROM hacks.",
		github = "CyanSMP64/NatDexExtension", -- Replace "MyUsername" and "ExtensionRepo" to match your GitHub repo url, if any

		requiredVersion = "v9.3.0", -- minimum Tracker version required to use this extension with full support
		extensionKey = "NatDexExtension", -- matches the name of this file, used for enabling/disabling this extension
    	isNatDex = false, -- a stored verification check if this game rom is a nat. dex game rom
		allowWarningPopup = true, -- if tracker doesn't support this extension, popup a warning
		monCountAddress = 0x08000170,
		romVersionMajorAddr = 0x0800048c,
		romVersionMinorAddr = 0x0800048d,
		romVersionPatchAddr = 0x0800048e,
		romVersionBuildAddr = 0x08000490,
	}
	self.url = string.format("https://github.com/%s", self.github or "")

	self.Paths = {
		RandomizerSettings = {
			folderNames = { "natdex", "rnqs_files", }, -- ordered; to create the folder path
			fileType = ".rnqs",
			builtPath = "/",  -- path to randomizer settings files, built later in startup()
		},
		PokemonSprites = {
			folderNames = { "natdex", "sprites_mons", }, -- ordered; to create the folder path
			fileType = ".png",
			builtPath = "/",  -- path to new nat. dex "pokemon" icon sprites, built later in startup()
		},
		TypeSprites = {
			folderNames = { "natdex", "sprites_types", }, -- ordered; to create the folder path
			fileType = ".png",
			builtPath = "/",  -- path to new nat. dex "type" icon sprites, built later in startup()
		},
	}

	-- local DEBUG_MESSAGES_ON = false

	-- Returns true if the Tracker code supports this Nat. Dex rom hack
	function self.checkIfTrackerVersionSupported()
		if GameSettings and GameSettings.RomHackSupport and GameSettings.RomHackSupport.NatDex then
			return true
		end

		self.isNatDex = false

		if self.allowWarningPopup then
			-- Pop up a delayed warning to notify that the current tracker needs updating to use this extension
			-- Also disable this extension to prevent future warnings
			Program.addFrameCounter("NatDexWarning", 5, function()
				local warningMessage = string.format("The Nat. Dex extension requires Tracker %s or higher.\n\nPlease update your Tracker before using this extension.", self.requiredVersion)
				Main.DisplayError(warningMessage, "Update", function()
					Program.changeScreenView(UpdateScreen)
					if Main.IsOnBizhawk() then client.unpause() end
				end)
				CustomCode.disableExtension(self.extensionKey or "NatDexExtension")
			end, 1)
		end
		return false
	end

	-- Returns true if the loaded game rom is a Nat. Dex game rom
	function self.checkIfNatDexROM()
		local natDexMonCount = Memory.read32(self.monCountAddress)
		return (natDexMonCount == 1258)
    end

	function self.buildExtensionPaths()
		-- Build file/folder paths to custom images and other resources
		for _, pathTable in pairs(self.Paths or {}) do
			local folderPath = table.concat(pathTable.folderNames or {}, FileManager.slash)
			pathTable.builtPath = FileManager.getCustomFolderPath() .. folderPath .. FileManager.slash
		end
	end

	function self.overrideTrackerSettings()
		-- Force using the gen7+ icon set
		self.currIconSet = tonumber(Options["Pokemon icon set"]) or 1
		Options.addUpdateSetting("Pokemon icon set", 3) -- gen 7+

		-- Change Log Viewer Pokemon display names to use Tracker-defined data instead
		self.currNamesFromLogSetting = RandomizerLog.Settings.UsePokemonNamesFromLog
		RandomizerLog.Settings.UsePokemonNamesFromLog = false
	end

	function self.undoOverrideTrackerSettings()
		if self.currIconSet ~= nil then
			Options.addUpdateSetting("Pokemon icon set", self.currIconSet)
			if Options.getIconSet().isAnimated then
				SpriteData.changeIconSet(self.currIconSet)
			end
		end
		if self.currNamesFromLogSetting ~= nil then
			RandomizerLog.Settings.UsePokemonNamesFromLog = self.currNamesFromLogSetting
		end
	end

	function self.overrideCoreTrackerFunctions()
		self.currentGetRandomizerSettingsPath = FileManager.getRandomizerSettingsPath
		FileManager.getRandomizerSettingsPath = self.overrideGetRandomizerSettingsPath

		self.currentTryLoadFunc = PokemonRevoData.tryLoadData
		PokemonRevoData.tryLoadData = self.overrideTryLoadRevoData

		self.currentDexMapInternalToNational = PokemonData.dexMapInternalToNational
		PokemonData.dexMapInternalToNational = self.overrideDexMapInternalToNational

		self.currentDexMapNationalToInternal = PokemonData.dexMapNationalToInternal
		PokemonData.dexMapNationalToInternal = self.overrideDexMapNationalToInternal

		if Tracker.TrackAbility ~= self.overrideTrackAbility then
			self.currentTrackAbility = Tracker.TrackAbility
			Tracker.TrackAbility = self.overrideTrackAbility
		end

		if Tracker.setAbilities ~= self.overrideSetAbilities then
			self.currentSetAbilities = Tracker.setAbilities
			Tracker.setAbilities = self.overrideSetAbilities
		end

		if Tracker.TrackStatMarking ~= self.overrideTrackStatMarking then
			self.currentTrackStatMarking = Tracker.TrackStatMarking
			Tracker.TrackStatMarking = self.overrideTrackStatMarking
		end

		if Tracker.TrackMove ~= self.overrideTrackMove then
			self.currentTrackMove = Tracker.TrackMove
			Tracker.TrackMove = self.overrideTrackMove
		end
	end

	function self.undoOverrideCoreTrackerFunctions()
		if type(self.currentGetRandomizerSettingsPath) == "function" then
			FileManager.getRandomizerSettingsPath = self.currentGetRandomizerSettingsPath
		end
		if type(self.currentTryLoadFunc) == "function" then
			PokemonRevoData.tryLoadData = self.currentTryLoadFunc
		end
		if type(self.currentDexMapInternalToNational) == "function" then
			PokemonData.dexMapInternalToNational = self.currentDexMapInternalToNational
		end
		if type(self.currentDexMapNationalToInternal) == "function" then
			PokemonData.dexMapNationalToInternal = self.currentDexMapNationalToInternal
		end
		if type(self.currentTrackAbility) == "function" then
			Tracker.TrackAbility = self.currentTrackAbility
		end
		if type(self.currentSetAbilities) == "function" then
			Tracker.setAbilities = self.currentSetAbilities
		end
		if type(self.currentTrackStatMarking) == "function" then
			Tracker.TrackStatMarking = self.currentTrackStatMarking
		end
		if type(self.currentTrackMove) == "function" then
			Tracker.TrackMove = self.currentTrackMove
		end
	end

