	self.LinkedAbilitySpecies = {}
	for groupIndex, speciesGroup in ipairs(self.LinkedAbilityGroups) do
		for _, speciesId in ipairs(speciesGroup) do
			self.LinkedAbilitySpecies[speciesId] = groupIndex
		end
	end

	self.LinkedManualHpSpecies = {}
	for groupIndex, speciesGroup in ipairs(self.LinkedManualHpGroups) do
		for _, speciesId in ipairs(speciesGroup) do
			self.LinkedManualHpSpecies[speciesId] = groupIndex
		end
	end

	self.LinkedManualAllStatSpecies = {}
	for groupIndex, speciesGroup in ipairs(self.LinkedManualAllStatGroups) do
		for _, speciesId in ipairs(speciesGroup) do
			self.LinkedManualAllStatSpecies[speciesId] = groupIndex
		end
	end

	self.LinkedTrackedMoveSpecies = {}
	for groupIndex, speciesGroup in ipairs(self.LinkedTrackedMoveGroups) do
		for _, speciesId in ipairs(speciesGroup) do
			self.LinkedTrackedMoveSpecies[speciesId] = groupIndex
		end
	end

	function self.shouldLinkAbilities(pokemonID)
		return self.LinkedAbilitySpecies[pokemonID or 0] ~= nil
	end

	function self.getLinkedAbilityGroupSpecies(pokemonID)
		local groupIndex = self.LinkedAbilitySpecies[pokemonID or 0]
		if groupIndex == nil then
			return nil
		end
		return self.LinkedAbilityGroups[groupIndex]
	end

	function self.getLinkedManualHpGroupSpecies(pokemonID)
		local groupIndex = self.LinkedManualHpSpecies[pokemonID or 0]
		if groupIndex == nil then
			return nil
		end
		return self.LinkedManualHpGroups[groupIndex]
	end

	function self.getLinkedManualAllStatGroupSpecies(pokemonID)
		local groupIndex = self.LinkedManualAllStatSpecies[pokemonID or 0]
		if groupIndex == nil then
			return nil
		end
		return self.LinkedManualAllStatGroups[groupIndex]
	end

	function self.getLinkedTrackedMoveGroupSpecies(pokemonID)
		local groupIndex = self.LinkedTrackedMoveSpecies[pokemonID or 0]
		if groupIndex == nil then
			return nil
		end
		return self.LinkedTrackedMoveGroups[groupIndex]
	end

	function self.shouldSkipLinkedTrackAbility(pokemonID, abilityId)
		if pokemonID == nil or abilityId == nil then
			return false
		end

		local trackedPokemon = Tracker.getOrCreateTrackedPokemon(pokemonID, false)
		local abilities = trackedPokemon.abilities or {}
		local ability1 = (abilities[1] or {}).id or 0
		local ability2 = (abilities[2] or {}).id or 0

		return ability1 == abilityId or ability2 == abilityId
	end

	function self.shouldSkipLinkedTrackMove(pokemonID, moveId, level)
		if pokemonID == nil or moveId == nil then
			return false
		end

		local trackedPokemon = Tracker.getOrCreateTrackedPokemon(pokemonID, false)
		for _, move in pairs(trackedPokemon.moves or {}) do
			if move.id == moveId then
				local minLv = move.minLv or move.level
				local maxLv = move.maxLv or move.level
				if level == nil or (minLv ~= nil and maxLv ~= nil and level >= minLv and level <= maxLv) then
					return true
				end
			end
		end

		return false
	end

	function self.shouldSkipLinkedTrackStatMarking(pokemonID, statStage, statState)
		if pokemonID == nil or statStage == nil or statState == nil then
			return false
		end

		local trackedPokemon = Tracker.getOrCreateTrackedPokemon(pokemonID, false)
		local markings = trackedPokemon.sm or {}
		return (markings[statStage] or 0) == statState
	end

	function self.overrideTrackAbility(pokemonID, abilityId)
		if type(self.currentTrackAbility) ~= "function" then
			return
		end

		self.currentTrackAbility(pokemonID, abilityId)

		if not self.shouldLinkAbilities(pokemonID) then
			return
		end

		local linkedSpecies = self.getLinkedAbilityGroupSpecies(pokemonID)
		if linkedSpecies == nil then
			return
		end

		for _, linkedSpeciesId in ipairs(linkedSpecies) do
			if linkedSpeciesId ~= pokemonID then
				if not self.shouldSkipLinkedTrackAbility(linkedSpeciesId, abilityId) then
					self.currentTrackAbility(linkedSpeciesId, abilityId)
				end
			end
		end
	end

	function self.overrideSetAbilities(pokemonID, abilityOneText, abilityTwoText)
		if type(self.currentSetAbilities) ~= "function" then
			return
		end

		self.currentSetAbilities(pokemonID, abilityOneText, abilityTwoText)

		if not self.shouldLinkAbilities(pokemonID) then
			return
		end

		local linkedSpecies = self.getLinkedAbilityGroupSpecies(pokemonID)
		if linkedSpecies == nil then
			return
		end

		for _, linkedSpeciesId in ipairs(linkedSpecies) do
			if linkedSpeciesId ~= pokemonID then
				self.currentSetAbilities(linkedSpeciesId, abilityOneText, abilityTwoText)
			end
		end
	end

	function self.overrideTrackStatMarking(pokemonID, statStage, statState)
		if type(self.currentTrackStatMarking) ~= "function" then
			return
		end

		self.currentTrackStatMarking(pokemonID, statStage, statState)

		local linkedAllStatSpecies = self.getLinkedManualAllStatGroupSpecies(pokemonID)
		if linkedAllStatSpecies ~= nil then
			for _, linkedSpeciesId in ipairs(linkedAllStatSpecies) do
				if linkedSpeciesId ~= pokemonID then
					if not self.shouldSkipLinkedTrackStatMarking(linkedSpeciesId, statStage, statState) then
						self.currentTrackStatMarking(linkedSpeciesId, statStage, statState)
					end
				end
			end
			return
		end

		if statStage ~= "hp" then
			return
		end

		local linkedSpecies = self.getLinkedManualHpGroupSpecies(pokemonID)
		if linkedSpecies == nil then
			return
		end

		for _, linkedSpeciesId in ipairs(linkedSpecies) do
			if linkedSpeciesId ~= pokemonID then
				if not self.shouldSkipLinkedTrackStatMarking(linkedSpeciesId, statStage, statState) then
					self.currentTrackStatMarking(linkedSpeciesId, statStage, statState)
				end
			end
		end
	end

	function self.overrideTrackMove(pokemonID, moveId, level)
		if type(self.currentTrackMove) ~= "function" then
			return
		end

		self.currentTrackMove(pokemonID, moveId, level)

		local linkedSpecies = self.getLinkedTrackedMoveGroupSpecies(pokemonID)
		if linkedSpecies == nil then
			return
		end

		for _, linkedSpeciesId in ipairs(linkedSpecies) do
			if linkedSpeciesId ~= pokemonID then
				if not self.shouldSkipLinkedTrackMove(linkedSpeciesId, moveId, level) then
					self.currentTrackMove(linkedSpeciesId, moveId, level)
				end
			end
		end
	end

	function self.overrideGetRandomizerSettingsPath()
		return self.Paths.RandomizerSettings.builtPath or "/"
	end

	function self.overrideGameSettingsInitialize()
		if type(self.currentGameSettingsInitialize) == "function" then
			self.currentGameSettingsInitialize()
		end

		if not self.checkIfNatDexROM() then
			self.isNatDex = false
			return
		end

		self.isNatDex = true
		self.updateProgramAddresses()
		self.updateGameSettings()
		self.updateFriendshipValues()
	end

	function self.addUpdateNewData()
		-- Add new Nat Dex data
		self.addNewEvoStones()
		self.addNewEvoDetails()
		self.addNewBattleItems()
		self.addNewOtherItems()
		self.addNewPokemonData()
		self.addNewMoves()
		self.addNewAbilities()
		self.addNewTypes()
		self.addNewSprites()
		self.addResources()

		-- Update existing data to Nat Dex
		self.updateResources()
		self.updatePokeData()
		self.updateMoveData()
		self.updateAbilityData()
		self.updateProgramAddresses()
		self.updateGameSettings()
		self.updateFriendshipValues()

		-- Rebuild the Tracker's data objects
		PokemonData.buildData(true)
		MoveData.buildData(true)
		AbilityData.buildData(true)

		-- update resources for Tracker's data objects
		PokemonData.updateResources()
		MoveData.updateResources()
		AbilityData.updateResources()
		MiscData.updateResources()
	end

	-- INTERNAL TRACKER FUNCTIONS
	-- Executed only once: When the Tracker starts up but before game data is loaded
	function self.beforeGameDataLoad()
		if not self.checkIfTrackerVersionSupported() then
			return
		end

		if type(self.currentGameSettingsInitialize) ~= "function" then
			self.currentGameSettingsInitialize = GameSettings.initialize
			GameSettings.initialize = self.overrideGameSettingsInitialize
		end
	end

	-- Executed only once: When the extension is enabled by the user, and/or when the Tracker first starts up, after it loads all other required files and code
	function self.startup()
		if not self.checkIfTrackerVersionSupported() then
			return
		end

        self.isNatDex = self.checkIfNatDexROM()
        if not self.isNatDex then
			-- if DEBUG_MESSAGES_ON then
	        --     Utils.printDebug("\nNat. Dex ROM not detected. Extension disabled.")
			-- end
            return
		end

		-- if DEBUG_MESSAGES_ON then
		-- 	Utils.printDebug("\nNat. Dex ROM detected. Extension enabled.")
		-- end

		self.buildExtensionPaths()
		self.overrideTrackerSettings()
		self.overrideCoreTrackerFunctions()
		self.addUpdateNewData()
		self.addGameOverInfo()
	end

	-- Executed only once: When the extension is disabled by the user, necessary to undo any customizations, if able
	function self.unload()
		if type(self.currentGameSettingsInitialize) == "function" then
			GameSettings.initialize = self.currentGameSettingsInitialize
			self.currentGameSettingsInitialize = nil
		end

		if not self.isNatDex then
			return
		end

		self.undoOverrideTrackerSettings()
		self.undoOverrideCoreTrackerFunctions()

		-- Force tracker to refresh and reload its scripts, removing all Nat. Dex changes
		Main.forceRestart = true

		-- if DEBUG_MESSAGES_ON then
		-- 	Utils.printDebug("\nNat. Dex extension disabled.")
		-- end
		self.removeGameOverInfo()
	end

	-- Executed when the user clicks the "Check for Updates" button while viewing the extension details within the Tracker's UI
	function self.checkForUpdates()
		local versionResponsePattern = '"tag_name":%s+"%w+(%d+%.%d+%.%d+%.?%d*)"' -- matches "1.0" in "tag_name": "v1.0"
		local versionCheckUrl = string.format("https://api.github.com/repos/%s/releases/latest", self.github or "")
		local downloadUrl = string.format("%s/releases/latest", self.url or "")
		local compareFunc = function(a, b) return a ~= b and not Utils.isNewerVersion(a, b) end -- if current version is *older* than online version
		local isUpdateAvailable = Utils.checkForVersionUpdate(versionCheckUrl, self.version, versionResponsePattern, compareFunc)
		return isUpdateAvailable, downloadUrl
	end

