	}

	function self.addNewPokemonData()
		-- Don't add new mons if they've already been added
		if PokemonData.Pokemon[412] ~= nil then
			return
		end

		for _, mon in ipairs(self.Data.natDexMons) do -- ipairs required for ordered lists
			-- Insert new mons at the end of the existing pokemon data table
			table.insert(PokemonData.Pokemon, mon)
		end
	end

	function self.addNewMoves()
		-- Don't add new moves if they've already been added
		if MoveData.Moves[355] ~= nil then
			return
		end

		for _, move in ipairs(self.Data.natDexMoves) do
			table.insert(MoveData.Moves, move)
		end
	end

	function self.addNewAbilities()
		-- Don't add new moves if they've already been added
		if AbilityData.Abilities[78] ~= nil then
			return
		end

		for _, move in ipairs(self.Data.natDexAbilities) do
			table.insert(AbilityData.Abilities, move)
		end
	end

	function self.addNewSprites()
		-- New Pokemon icons
		Drawing.ImagePaths.PokemonIcon.getOverridePath = function(this, value)
			return self.Paths.PokemonSprites.builtPath .. value .. self.Paths.PokemonSprites.fileType
		end
		Drawing.ImagePaths.PokemonIcon.shouldUseOverride = function(this, value)
			-- Only use custom path if it's a new pokemon (gen4+)
			return (tonumber(value) or 0) > 411
		end

		-- New Pokemon types
		Drawing.ImagePaths.PokemonType.getOverridePath = function(this, value)
			return self.Paths.TypeSprites.builtPath .. value .. self.Paths.TypeSprites.fileType
		end
		Drawing.ImagePaths.PokemonType.shouldUseOverride = function(this, value)
			-- Only use custom path if it's the fairy type
			return value == "fairy"
		end
	end

	function self.addNewEvoStones()
		-- Don't add new stones if they've already been added
		if MiscData.EvolutionStones[99] ~= nil then
			return
		end
		for id, item in pairs(self.Data.natDexEvoStones) do
			MiscData.EvolutionStones[id] = item
		end
	end

	function self.addNewBattleItems()
		-- Don't add new stones if they've already been added
		if MiscData.BattleItems[82] ~= nil then
			return
		end
		for id, item in pairs(self.Data.natDexBattleItems) do
			MiscData.BattleItems[id] = item
		end
	end

	function self.addNewOtherItems()
		-- Don't add new stones if they've already been added
		if MiscData.OtherItems[52] ~= nil then
			return
		end
		for id, item in pairs(self.Data.natDexOtherItems) do
			MiscData.OtherItems[id] = item
		end
	end

	function self.addNewTypes()
		-- Don't add new types if they've already been added
		if PokemonData.Types.FAIRY ~= nil then
			return
		end
		for id, item in pairs(self.Data.natDexTypes) do
			PokemonData.Types[id] = item
		end
		for id, item in pairs(self.Data.natDexTypeCategories) do
			MoveData.TypeToCategory[id] = item
		end
		for id, item in pairs(self.Data.natDexTypeEffectiveness) do
			MoveData.TypeToEffectiveness[id] = item
		end
		if #CoverageCalcScreen.OrderedTypeKeys < 18 then
			-- Add extra type to the screen, then rebuild it via `initialize()`
			table.insert(CoverageCalcScreen.OrderedTypeKeys, "FAIRY")
			CoverageCalcScreen.initialize()
		end
	end

	function self.addNewEvoDetails()
		-- Don't add new evo details if they've already been added
		if PokemonData.Evolutions.SHINY ~= nil then
			return
		end
		for id, item in pairs(self.Data.natDexEvoDetails) do
			PokemonData.Evolutions[id] = item
		end
	end

